final class PasswordResetRouter {
    static let shared = PasswordResetRouter()
    private init() {}

    func presentResetScreen(token: String) {
        DispatchQueue.main.async {
            guard let top = Self.topViewController() else { return }
            let resetView = PasswordResetView(token: token)
            let hosting = UIHostingController(rootView: resetView)
            hosting.modalPresentationStyle = .fullScreen
            top.present(hosting, animated: true)
        }
    }

    private static func topViewController(base: UIViewController? = UIApplication.shared.connectedScenes
        .compactMap { $0 as? UIWindowScene }
        .flatMap { $0.windows }
        .first(where: { $0.isKeyWindow })?.rootViewController) -> UIViewController? {
        if let nav = base as? UINavigationController {
            return topViewController(base: nav.visibleViewController)
        }
        if let tab = base as? UITabBarController {
            return topViewController(base: tab.selectedViewController)
        }
        if let presented = base?.presentedViewController {
            return topViewController(base: presented)
        }
        return base
    }
}

struct PasswordResetView: View {
    let token: String

    @State private var newPassword = ""
    @State private var confirmPassword = ""
    @State private var isSubmitting = false
    @State private var errorMessage: String?
    @State private var successMessage: String?

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("Reset Password")) {
                    SecureField("New Password", text: $newPassword)
                    SecureField("Confirm Password", text: $confirmPassword)
                }

                if let errorMessage {
                    Section {
                        Text(errorMessage)
                            .foregroundColor(.red)
                    }
                }

                if let successMessage {
                    Section {
                        Text(successMessage)
                            .foregroundColor(.green)
                    }
                }

                Section {
                    Button(action: submit) {
                        if isSubmitting {
                            ProgressView()
                        } else {
                            Text("Update Password")
                        }
                    }
                    .disabled(isSubmitting || newPassword.isEmpty || confirmPassword.isEmpty)
                }
            }
            .navigationTitle("Reset Password")
        }
    }

    private func submit() {
        guard newPassword == confirmPassword else {
            errorMessage = "Passwords do not match."
            successMessage = nil
            return
        }

        isSubmitting = true
        errorMessage = nil
        successMessage = nil

        PasswordResetAPI.resetPassword(token: token, newPassword: newPassword) { result in
            DispatchQueue.main.async {
                isSubmitting = false
                switch result {
                case .success:
                    successMessage = "Your password has been updated."
                case .failure(let error):
                    errorMessage = error.localizedDescription
                }
            }
        }
    }
}

enum PasswordResetAPI {
    static func resetPassword(token: String, newPassword: String, completion: @escaping (Result<Void, Error>) -> Void) {
        guard let url = URL(string: "https://myapp.com/api/reset-password") else {
            completion(.failure(NSError(domain: "PasswordResetAPI", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid API URL"])))
            return
        }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let body: [String: Any] = [
            "token": token,
            "newPassword": newPassword
        ]

        request.httpBody = try? JSONSerialization.data(withJSONObject: body, options: [])

        URLSession.shared.dataTask(with: request) { _, response, error in
            if let error {
                completion(.failure(error))
                return
            }

            let http = response as? HTTPURLResponse
            guard (200...299).contains(http?.statusCode ?? 0) else {
                completion(.failure(NSError(domain: "PasswordResetAPI", code: http?.statusCode ?? -1, userInfo: [NSLocalizedDescriptionKey: "Failed to reset password"])))
                return
            }

            completion(.success(()))
        }.resume()
    }
}

